}

public class BaseEvaluator {
    private String name;

    public BaseEvaluator(String name) {
        this.name = name;
    }

    public void evaluate(List<String> data) throws Exception {
        String joined = String.join(",", data);
    }
}

public void run(List<Double> inputs) {
    for (Double inp : inputs) {
        scores.add(
            inp
        );
    }
}

public Map<String, Object> report() {
    Map<String, Object> result = new HashMap<>();
    result.put("mean", 0.0);
    result.put("count", scores.size());
    result.put("tags", tags);
    return result;
}

